App javascript (Consolidar as fontes das planilhas da 04 equipes do orçamento numa planilha google)

/**
 * Atualiza uma planilha destino com dados de TRÊS planilhas de origem (Excel)
 * Consolida os dados, normaliza colunas e limpa quebras de linha.
 * Adiciona a Coluna W com o número da fonte (1, 2 ou 3).
 */
function atualizarPlanilhaDestino_TresFontes() {
  // 1️⃣ IDs das Planilhas de Origem (Excel)
  const origemExcelId1 = "1jAfqnRbS21EwBfYQyTaX_PmTeNt4wRXa"; 
  const origemExcelId2 = "1TCxuRgg8bDk8Pm8reQfqBOUpJN0bCjRn"; 
  const origemExcelId3 = "1nImagH2AnPshdh145QhrK6vqqOeD0jG-"; 

  const destinoId = "1DuE28zYpZx6W6l3rFbRbxfBevecwMmb3XXOnXGXUOkI"; 

  const destinoSheet = SpreadsheetApp.openById(destinoId).getSheets()[0];
  let todosOsDados = [];
  
  // Definimos que a largura mínima deve ser 23 para alcançar a coluna W
  let maxColunas = 23; 

  const fontes = [origemExcelId1, origemExcelId2, origemExcelId3];

  fontes.forEach((id, index) => {
    const file = DriveApp.getFileById(id);
    const blob = file.getBlob();

    const resource = {
      name: "TEMP_CONVERT_" + index + "_" + file.getName(),
      mimeType: MimeType.GOOGLE_SHEETS,
    };
    
    const converted = Drive.Files.create(resource, blob);
    const origemSheet = SpreadsheetApp.openById(converted.id).getSheets()[0];
    const dadosFonte = origemSheet.getDataRange().getValues();

    // Identificador da fonte (1, 2 ou 3)
    const numeroDaFonte = index + 1;

    for (let r = 0; r < dadosFonte.length; r++) {
      // Pula o cabeçalho da 2ª e 3ª planilha
      if (index > 0 && r === 0) continue; 

      let linha = dadosFonte[r];

      // Limpeza de caracteres e quebras de linha
      for (let c = 0; c < linha.length; c++) {
        if (linha[c] !== null && linha[c] !== '') {
          linha[c] = String(linha[c])
            .replace(/[\r\n]+/g, ' ')
            .replace(/\s+/g, ' ')
            .trim();
        } else {
          linha[c] = '';
        }
      }

      // Preenche a linha até a coluna V (índice 21) para que a Fonte caia na W (índice 22)
      while (linha.length < 22) {
        linha.push("");
      }

      // Adiciona o valor na Coluna W
      if (index === 0 && r === 0) {
        linha[22] = "FONTE ORIGEM"; // Cabeçalho
      } else {
        linha[22] = numeroDaFonte; // 1, 2 ou 3
      }

      // Atualiza o maxColunas se a linha original for maior que 23
      maxColunas = Math.max(maxColunas, linha.length);
      
      todosOsDados.push(linha);
    }

    DriveApp.getFileById(converted.id).setTrashed(true);
  });

  // 3️⃣ Normalização: Garante que todas as linhas tenham o mesmo tamanho final
  todosOsDados = todosOsDados.map(linha => {
    while (linha.length < maxColunas) {
      linha.push(""); 
    }
    return linha;
  });

  // 4️⃣ Limpa o destino e cola os dados
  destinoSheet.clear(); 
  
  if (todosOsDados.length > 0) {
    const rangeDestino = destinoSheet.getRange(1, 1, todosOsDados.length, maxColunas);
    rangeDestino.setValues(todosOsDados);
    
    rangeDestino.setWrap(false);
    
    const merged = rangeDestino.getMergedRanges();
    if (merged && merged.length > 0) {
      merged.forEach(r => r.breakApart());
    }
    
    const alturaPadrao = 21; 
    destinoSheet.setRowHeights(1, todosOsDados.length, alturaPadrao);
  }

  SpreadsheetApp.flush();
  Logger.log("✅ Dados consolidados com identificação da fonte na Coluna W!");
}

